// Retrieve audit logs
app.get('/api/audit/logs', (req, res) => {
    const { username, startDate, endDate, action } = req.query;
    const clientIp = req.headers['x-forwarded-for'] || req.ip;

    auditLogger.info(`Audit logs retrieved by ${username}`, {
        action: 'AUDIT_LOG_ACCESS',
        username,
        filters: { startDate, endDate, action },
        ip: clientIp
    });

    // Read and return recent audit logs
    const auditLogPath = path.join(logsDir, 'audit.log');
    if (fs.existsSync(auditLogPath)) {
        const logs = fs.readFileSync(auditLogPath, 'utf8');
        const lines = logs.split('\n').filter(Boolean).slice(-100); // Last 100 entries
        res.json({ success: true, logs: lines });
    } else {
        res.json({ success: true, logs: [] });
    }
});

// Error handling middleware
app.use((err, req, res, next) => {
    const clientIp = req.headers['x-forwarded-for'] || req.ip;
    const username = req.headers['x-username'] || req.body?.username || 'unknown';

    auditLogger.error(`Unhandled error: ${err.message}`, {
        action: 'ERROR',
        username,
        ip: clientIp,
        path: req.path,
        method: req.method,
        stack: err.stack
    });

    res.status(500).json({ success: false, message: 'Internal server error' });
});

// 404 handler
app.use((req, res) => {
    const clientIp = req.headers['x-forwarded-for'] || req.ip;

    auditLogger.warn(`404 Not Found: ${req.method} ${req.originalUrl}`, {
        action: 'NOT_FOUND',
        ip: clientIp,
        method: req.method,
        path: req.originalUrl,
        userAgent: req.headers['user-agent']
    });

    res.status(404).json({ success: false, message: 'Endpoint not found' });
});

// Start server
app.listen(PORT, () => {
    auditLogger.info(`Audit Logging System started on port ${PORT}`, {
        action: 'SERVER_START',
        port: PORT,
        environment: process.env.NODE_ENV || 'development'
    });
    console.log(`Server running on http://localhost:${PORT}`);
});

module.exports = app;